const express = require('express');
const httpProxy = require('http-proxy');
const bodyParser = require('body-parser');

const app = express();
const proxy = httpProxy.createProxyServer({});

app.use(bodyParser.json());

const loadPlugins = () => {
  const plugins = [];
  const pluginConfigs = process.env.PLUGIN_CONFIGS ? JSON.parse(process.env.PLUGIN_CONFIGS) : [];

  pluginConfigs.forEach(config => {
    try {
      if (config.type === 'file') {
        const plugin = require(config.path);
        plugins.push(plugin);
      } else if (config.type === 'code') {
        const plugin = eval(config.code);
        plugins.push(plugin);
      }
    } catch (error) {
      console.error('Error loading plugin:', error);
    }
  });

  return plugins;
};

const plugins = loadPlugins();

app.use((req, res, next) => {
  plugins.forEach(plugin => {
    if (typeof plugin.modifyRequest === 'function') {
      plugin.modifyRequest(req);
    }
  });
  next();
});

app.use((req, res, next) => {
  res.on('finish', () => {
    plugins.forEach(plugin => {
      if (typeof plugin.modifyResponse === 'function') {
        plugin.modifyResponse(res);
      }
    });
  });
  next();
});

app.all('*', (req, res) => {
  const target = req.headers['x-target-url'];
  if (!target) {
    return res.status(400).send('Target URL header is missing');
  }

  proxy.web(req, res, { target }, err => {
    res.status(500).send('Proxy error');
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`API Gateway running on port ${PORT}`);
});